test_that("best_global_ci_split_cpp matches R scoring with tied ranks", {
  predictors <- data.frame(
    z = c(1, 2, 3, 4, 5, 6, 7, 8),
    group = factor(c("a", "a", "b", "b", "c", "c", "d", "d"))
  )
  y <- cbind(
    rank = c(10, 20, 20, 40, 40, 60, 60, 80),
    outcome = c(0, 0, 1, 1, 4, 4, 5, 5)
  )
  wt <- c(1, 3, 2, 1, 4, 2, 5, 1)
  ctrl <- ci_tree_control(minsplit = 1, minbucket = 1, minprob = 0)

  current <- best_global_ci_split(
    x = predictors,
    y = y,
    wt = wt,
    ctrl = ctrl,
    ci_fun = ci_factory("CIg")
  )
  cpp <- best_global_ci_split_cpp(
    x = predictors,
    y = y,
    wt = wt,
    ctrl = ctrl,
    type = "CIg"
  )

  expect_equal(cpp$gain, current$gain, tolerance = 1e-12)
  expect_equal(cpp$varid, current$varid)
  expect_equal(cpp$left, current$left)
})

test_that("best_global_ci_split_cpp respects min_relative_gain", {
  predictors <- data.frame(
    x = c(1, 2, 3, 4, 5, 6, 7)
  )
  y <- cbind(
    rank = c(20, 10, 40, 30, 70, 50, 60),
    outcome = c(1, 0, 1, 0, 1, 0, 1)
  )
  wt <- c(1, 3, 2, 4, 1, 2, 5)
  ctrl <- ci_tree_control(
    minsplit = 1,
    minbucket = 1,
    minprob = 0,
    min_relative_gain = 0
  )

  split <- best_global_ci_split_cpp(
    x = predictors,
    y = y,
    wt = wt,
    ctrl = ctrl,
    type = "CIg"
  )

  expect_true(is.finite(split$relative_gain))
  expect_equal(split$parent_impurity, ci_factory("CIg")(y, wt))
  expect_equal(split$relative_gain, split$gain / abs(split$parent_impurity))

  ctrl$min_relative_gain <- split$relative_gain + 1e-8
  expect_null(best_global_ci_split_cpp(
    x = predictors,
    y = y,
    wt = wt,
    ctrl = ctrl,
    type = "CIg"
  ))
})

test_that("best_factor_split_cpp uses exact partition search when requested", {
  x_full <- factor(rep(letters[1:4], each = 4), levels = letters[1:4])
  keep <- rep(TRUE, 16)
  y_full <- cbind(
    rank = c(
      0.208, 0.307, 0.331, 0.199, 0.236, 0.275, 0.591, 0.253,
      0.123, 0.230, 0.598, 0.211, 0.464, 0.647, 0.961, 0.676
    ),
    outcome = c(
      2.281, 1.853, 2.333, 2.283, 1.301, 3.502, 2.120, 1.706,
      2.906, 4.838, 3.343, 3.161, 4.298, 3.896, 4.187, 0.548
    )
  )
  wt_full <- c(
    1.649, 1.998, 2.799, 2.957, 0.595, 1.945, 2.333, 1.122,
    1.252, 2.334, 2.767, 1.025, 1.395, 1.621, 2.766, 1.474
  )
  ctrl <- ci_tree_control(
    minsplit = 1,
    minbucket = 1,
    minprob = 0,
    factor_split = "partition",
    max_factor_partitions = 1e6
  )
  expected <- best_factor_split(
    x_full, keep, y_full, wt_full, 1, ctrl, ci_factory("CI"),
    return = "candidate"
  )
  cpp <- best_factor_split_cpp(
    x_full, keep, y_full, wt_full, 1, ctrl, type = "CI",
    return = "candidate"
  )

  expect_equal(cpp$factor_split, "partition")
  expect_equal(cpp$gain, expected$gain, tolerance = 1e-12)
  expect_equal(cpp$left_levels, expected$left_levels)
})

test_that("best_factor_split_cpp falls back to ordered factor search in auto mode", {
  x_full <- factor(rep(letters[1:4], each = 2), levels = letters[1:4])
  keep <- rep(TRUE, 8)
  y_full <- cbind(
    rank = seq_len(8),
    outcome = c(1, 2, 4, 3, 7, 6, 8, 5)
  )
  wt_full <- rep(1, 8)
  ctrl <- ci_tree_control(
    minsplit = 1,
    minbucket = 1,
    minprob = 0,
    factor_split = "auto",
    max_factor_partitions = 1
  )
  cpp <- best_factor_split_cpp(
    x_full, keep, y_full, wt_full, 1, ctrl, type = "CI",
    return = "candidate"
  )

  expect_equal(cpp$factor_split, "order")
})

test_that("best_global_ci_split_cpp rejects non-finite weights before C++", {
  predictors <- data.frame(x = c(1, 2, 3))
  y <- cbind(rank = c(10, 20, 30), outcome = c(1, 0, 1))
  ctrl <- ci_tree_control(minsplit = 1, minbucket = 1, minprob = 0)

  for (bad_weights in list(c(1, Inf, 1), c(1, NaN, 1), c(1, -Inf, 1))) {
    expect_error(
      best_global_ci_split_cpp(
        x = predictors,
        y = y,
        wt = bad_weights,
        ctrl = ctrl,
        type = "CI"
      ),
      "finite"
    )
  }
})
